var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 아쿠아리움, P. M. 19 : 37\\n<color=#ffd34c>조니 앤 멜로니</color> 대표 람다 스파타리, 비즈니스 미팅 중","JPN":"シャレードアクアリウム、P. M. 19 : 37\\n<color=#ffd34c>ジョニー＆メロニー</color>代表、ラムダ・スパタリー。ビジネスのミーティング中","ENG":"[[","TWN":"查雷德水族館，下午19:37\\n<color=#ffd34c>強尼&梅蘭妮</color>代表蘭達·史派特，商務會議中","THA":"พิพิธภัณฑ์สัตว์น้ำชาเรด 19.37 น.\\nCEOของ<color=#ffd34c>โจนีแอนด์เมโลนี</color>, แลมดา สปาตารี ในการพบปะทางธุรกิจ","VTN":"Thủy cung Charade, 19:37\\nCEO của<color=#ffd34c>Jonie & Melonie </color>, Lamda Spatari, trong một cuộc họp kinh doanh","SCN":"查雷德水族馆，下午19:37\\n<color=#ffd34c>乔尼&梅洛尼</color>拉姆达·斯帕塔里，商务会议中","DEU":"Charade Aquarium, 19:37 Uhr\\n<color=#ffd34c>Jonie & Melonie</color> Vorsitzende Lamda Spatari, bei einem Geschäftstreffen","FRA":"Aquarium de Charade, 19h37\\nLambda Spatari, Diretrice générale de <color=#ffd34c>Johnny & Melonie</color>, en réunion d'affaires"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"곧 마감 시간이라 그런지 한산하군요. 주말이랑은 전혀 다른 곳 같습니다.","JPN":"もうすぐ閉館の時間だからか、ずいぶんと静かですね。週末とはまったく別の場所のようです。","ENG":"It's quiet because it's nearly closing time. On weekends, it feels like a different place.","TWN":"不知道是不是因為快到關門時間了，好冷清啊。和週末簡直完全不一樣。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"직원들이 그러던데, 평소에도 동생 분과 자주 오신다면서요?","JPN":"職員から聞いたのですが、普段も妹さんとよく訪問されるそうですね。","ENG":"I heard from your staff that you come here often with your sister.","TWN":"聽職員們說，平時你也經常和妹妹一起來？"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"어떻습니까? 이번 주말에 바람도 쐴 겸 저희 가족들이랑 같이 오시는 건.","JPN":"どうですか？　今週末に気分転換も兼ねて、私の家族と一緒に来るのは。","ENG":"So how about joining me and my family for some fresh air this weekend?","TWN":"怎麼樣？這週末跟我們家人一起來，也順便兜兜風。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"아내가 뱅쇼를 참 잘 만듭니다. 저도 겨울철에 자주 얻어 먹죠.","JPN":"妻の作るホットワインが逸品なんです。私も冬にはよく飲んでいますよ。","ENG":"My wife makes a mean vin chaud. I drink a lot of it in the winter.","TWN":"我太太很會做熱紅酒。冬天我也經常跟著她喝。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"불쾌하게 남의 사생활을 캐고 다니지 마십시오, 대리인.","JPN":"人のプライベートを探らないでください、代理人。不愉快です。","ENG":"Please do not pry into the private lives of others.","TWN":"不要打聽別人的私生活，讓人很反感，代理人。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그런 저급한 태도가 회사의 이미지를 깎아내릴 수 있다는 것도 모릅니까?","JPN":"そのような低級な態度が、会社のイメージを傷つける結果につながりかねないということがわからないのですか？","ENG":"Don't you realize that kind of crass attitude harms the company's image?","TWN":"你不知道這種諂媚的態度，可能會損害公司形象嗎？"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"하, 하하… 샤레이드의 기업들은 늘 유능한 로펌과 친분을 유지하고 싶어하니까요.","JPN":"は、はは……シャレードの企業は常に有能なローファームと親交を深めたいと思っていますからね。","ENG":"Ha, haha... The companies at Charade are always eager to maintain positive relations with a competent law firm.","TWN":"哈，哈哈……因為查雷德的企業，總是想和有能力的律師事務所保持友好關係。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"특히 조니 앤 멜로니와는 더욱 그렇죠.","JPN":"ジョニー＆メロニーとは特にそうです。","ENG":"Especially more, if that firm is Jonie & Melonie.","TWN":"和強尼&梅蘭妮更是如此。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"규정에 따르면 이 아쿠아리움은 13분 뒤 폐관하게 되어 있습니다.","JPN":"規定によると、このアクアリウムは13分後に閉館することになっています。","ENG":"According to the aquarium's operating hours, it will close in 13 minutes.","TWN":"根據規定，這家水族館將在13分鐘後關門。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"잡설은 그만하고 용건을 말하세요.","JPN":"無駄話はやめて、用件を話してください。","ENG":"So stop with your nonsense and get to the point.","TWN":"廢話少說，說正事吧。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"크흠, 어쩔 수 없군요.","JPN":"コホン、仕方ありませんね。","ENG":"Ahem. Understood.","TWN":"咳呃，好吧。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"대표님, 와일러라고 들어 보셨습니까?","JPN":"代表、ワイラーについて聞いたことはありますか？","ENG":"Ma'am, have you ever heard of a man named Wyler?","TWN":"代表，你聽說過瓦勒嗎？"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"뉴스 속보로는. 치정 문제 때문에 건틀렛에서 상대 직원을 살해했다죠.","JPN":"ニュースの速報でなら。痴情のもつれが原因で、ガントレットで相手の職員を殺したらしいですね。","ENG":"According to the news, he had killed another employee at the Gauntlet out of jealousy.","TWN":"在新聞速報上看到過。因為婚外情的問題，在聖鎧殺害了對方的職員。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"그렇습니다. 그 남자를 보석으로 풀려나게 도와 주십시오.","JPN":"そうです。その男が保釈を認められるように手伝っていただきたいのです。","ENG":"Yes. I was wondering if you could assist us in getting him released on bail.","TWN":"是的，請你幫忙把那個男人保釋出來。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"수임료는 준비되었습니까?","JPN":"ペイは準備できていますか？","ENG":"Have you got my commission fee ready?","TWN":"委託費準備好了嗎？"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"물론이죠. 장거리 통신과 관련된 특허 2건을 양도해 드리겠습니다.","JPN":"もちろんです。長距離通信に関する特許を2件、お譲りしましょう。","ENG":"Of course. I will hand you 2 patents pertaining to long-distance communication.","TWN":"當然。我們會轉讓2項和長途通訊有關的專利給你。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};